mapper.update:
update
    dm_approval
set
    appro_identity = #{approvalIdentity},approval_url = #{url}
where id = #{ticketId}

update
    dm_approval
set
    appro_comment = #{comment}
where id = #{ticketId}

update
    dm_approval
set ticket_info = #{ticketInfo}
where id = #{ticketId}

mapper.select:
select

from
dm_approval

 AND owner_uid in #{item}
 AND gmt_create > #{ticketQuery.startTime} 
 AND gmt_create < #{ticketQuery.endTime} 
 AND id = #{ticketQuery.ticketId} 
 AND biz_id = #{ticketQuery.ticketBizId} 
 AND ticket_title LIKE concat('%',#{ticketQuery.ticketTitleName},'%') 
 AND ticket_status =#{ticketQuery.ticketStatus,javaType=com.clougence.clouddm.console.web.dal.enumeration.RdpTicketStatus} 
 AND bind_ds_id in #{item}
and primary_uid = #{puid}
and deleted = false

order by
gmt_create desc

select

from
dm_approval

    appro_identity = #{approIdentity}
    and appro_type = #{type}
    and deleted = false
     and primary_uid = #{puid}

select

from
dm_approval

     AND owner_uid in #{item}
     AND gmt_create > #{ticketQuery.startTime} 
     AND gmt_create < #{ticketQuery.endTime} 
     AND ticket_title LIKE concat('%',#{ticketQuery.ticketTitleName},'%') 
     AND ticket_status =#{ticketQuery.ticketStatus,javaType=com.clougence.clouddm.console.web.dal.enumeration.RdpTicketStatus} 
    and appro_biz = 'DATA_SOURCE_AUTH'
    and deleted = false

order by
gmt_create desc
